import { useEffect, useState } from 'react';

function Home() {
  const [imageLoaded, setImageLoaded] = useState(false);

  useEffect(() => {
    const img = new Image();
    img.src = '/fondo6.jpg';
    img.onload = () => {
      setImageLoaded(true);
    };
  }, []);

  return (
    <div className="w-full h-auto flex items-center justify-center p-4 relative md:p-10">
      {/* Fondo de baja calidad */}
      <div
        className={`absolute top-0 left-0 w-full h-full transition-opacity duration-1000 ease-in-out md:h-[125%] lg:h-[145%] ${
          imageLoaded ? 'opacity-0' : 'opacity-40'
        }`}
        style={{
          backgroundImage: `url('/fondo6_lazy.jpg')`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
        }}
      />

      {/* Fondo de alta calidad */}
      <div
        className={`absolute top-0 left-0 w-full h-full transition-opacity duration-1000 ease-in-out md:h-[125%] [145%] ${
          imageLoaded ? 'opacity-40' : 'opacity-0'
        }`}
        style={{
          backgroundImage: `url('/fondo6.jpg')`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
        }}
      />

      <div className="w-full h-full z-10 flex flex-col md:flex-row items-center justify-center gap-10 md:justify-between xl:px-[5%]">
        {/* Images left */}
        <div className="w-full h-[17rem] flex justify-end md:justify-start md:w-1/4">
          <div className="relative flex flex-col items-center md:ml-10">
            {/* Primera imagen */}
            <img
              id="image-1"
              className="w-[15rem] h-full rounded-lg transition-transform transform md:w-[10rem] md:h-[13rem] lg:w-[300px] lg:h-[400px]"
              src="/Foto1.HEIC"
              alt="Imagen 1"
            />
            {/* Segunda imagen */}
            <img
              id="image-2"
              className="w-[7rem] h-[8rem] top-[15%] left-[-40%] rounded-lg absolute animate-float md:w-[5rem] md:h-[7rem] md:top-[10%] md:left-[-40%] lg:left[-30%] xl:left-[-25%] xl:w-[7rem] xl:h-[9rem]"
              style={{
                transform: 'translateX(-50%) translateY(-10px)',
              }}
              src="/Foto5.JPEG"
              alt="Imagen 2"
            />
            {/* Tercera imagen */}
            <img
              id="image-3"
              className="w-[7rem] h-[8rem] top-[80%] left-[60%] rounded-lg absolute animate-float md:w-[5rem] md:h-[7rem] md:top-[70%] md:left-[30%] lg:top-[90%] xl:w-[7rem] xl:h-[10rem]"
              style={{
                transform: 'translateX(-50%) translateY(10px)',
              }}
              src="/Foto2.HEIC"
              alt="Imagen 3"
            />
          </div>
        </div>

        {/* Text center */}
        <div className="h-[15rem] flex flex-col justify-center items-center gap-5 text-center md:w-2/4">
          <h3 className="px-8 text-[#6d7561] text-2xl sm:text-3xl md:px-0 md:text-3xl font-medium">
            ¡Te invitamos a festejar nuestra boda!
          </h3>
          <h1 className="text-[#6d7561] text-3xl sm:text-4xl md:text-5xl font-bold">
            Anto & Kevin
          </h1>
          <a
            target="_blank"
            href="https://p02jvynd.forms.app/formularioinvitados"
            className="text-[#6d7561] text-xl sm:text-2xl underline hover:text-[#6d756190]"
          >
            Confirmar tu asistencia
          </a>
        </div>

        {/* Images right */}
        <div className="w-full h-[17rem] flex justify-start md:justify-end md:w-1/4">
          <div className="relative flex flex-col items-center md:ml-10">
            <img
              className="w-[15rem] h-full rounded-lg transition-transform transform md:w-[10rem] md:h-[13rem] lg:w-[300px] lg:h-[400px]"
              src="/Foto3.JPEG"
              alt="Imagen 1"
            />
            <img
              width={150}
              height={150}
              className="w-[7rem] h-[8rem] top-[-15%] right-[-20%] rounded-lg absolute animate-float md:w-[5rem] md:h-[7rem] md:top-[70%] md:right-[20%] lg:top-[100%] lg:right-[25%] xl:w-[7rem] xl:h-[10rem] xxl:top-[50%]"
              style={{
                transform: 'translateX(50%) translateY(-10px)',
              }}
              src="/Foto4.JPEG"
              alt="Imagen 2"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
